return $input.all()
  .map(i => i.json)
  .filter(r => r && (r.active === true || String(r.active).trim().toUpperCase() === 'TRUE'))
  .map(r => ({ json: { channel: String(r.channel).trim(), last_id: Number(r.last_id) || 0 } }));

function decode(s){
  return String(s)
    .replace(/<br\s*\/?>/gi,'\n')
    .replace(/<[^>]+>/g,'')
    .replace(/&#x([0-9a-fA-F]+);/g,(m,h)=>String.fromCodePoint(parseInt(h,16)))
    .replace(/&#(\d+);/g,(m,d)=>String.fromCodePoint(parseInt(d,10)))
    .replace(/&nbsp;/g,' ').replace(/&quot;/g,'"').replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&amp;/g,'&')
    .replace(/[ \t]+\n/g,'\n').replace(/\n{3,}/g,'\n\n').trim();
}
function parseAll(html){
  const posts=[]; const blocks=String(html).split('tgme_widget_message_wrap');
  for(const b of blocks){
    const dm=b.match(/data-post="([^"]+)"/); if(!dm) continue;
    const parts=dm[1].split('/'); const ch=parts[0]; const id=parseInt(parts[1]||'',10);
    if(!ch||!id) continue;
    const tm=b.match(/datetime="([^"]+)"/); const date=tm?tm[1]:'';
    const txm=b.match(/tgme_widget_message_text[^>]*>([\s\S]*?)<\/div>/); const text=txm?decode(txm[1]):'';
    posts.push({ id, channel: ch, date, text, link: 'https://t.me/'+ch+'/'+id });
  }
  return posts;
}
const chMap={};
for(const c of $('Активные каналы').all()){ chMap[c.json.channel]=Number(c.json.last_id)||0; }
const out=[];
for(const it of $input.all()){
  const html = it.json && it.json.data;
  if(typeof html!=='string') continue;
  for(const p of parseAll(html)){
    const last = chMap[p.channel]!=null ? chMap[p.channel] : 0;
    if(p.id>last) out.push({ json: p });
  }
}
return out;

const byCh={};
for(const it of $('Парсить посты').all()){
  const p=it.json; if(!p||!p.channel) continue;
  if(byCh[p.channel]==null || p.id>byCh[p.channel]) byCh[p.channel]=p.id;
}
return Object.keys(byCh).map(ch=>({ json:{ channel: ch, last_id: byCh[ch] } }));

const SYSTEM = `Ты обрабатываешь одно сообщение из Telegram-канала с вакансиями. Определи, вакансия это или нет (вакансия = конкретное предложение работы или проекта). Верни строго JSON, без пояснений и без markdown.

Профиль кандидата (Антон) и его 8 резюме под разные роли:
1. AI Automation Engineer: n8n (self-hosted, production, MCP), Claude API, OpenAI, агентные workflow, REST, webhooks, OAuth, Python (FastAPI), JS, Docker, Linux, VPS.
2. WordPress Developer: WordPress, кастомные плагины, ACF, темы, PHP, MySQL, REST API, Cloudflare, Core Web Vitals, WP Rocket, Yoast, Rank Math, Polylang.
3. Technical SEO: multi-GEO SEO, hreflang, Schema.org, Core Web Vitals, Ahrefs, GSC, GA4, crawl и index, anti-detect, proxy, n8n rank tracking, iGaming.
4. iGaming Creative Designer: баннеры и креативы (betting, casino, slots), Figma, Photoshop, Illustrator, AI-генерация (Midjourney, DALL-E, Leonardo).
5. Video Editor and Motion Designer: Premiere, After Effects, DaVinci, CapCut, AI-видео (Sora, Runway, Pika), AI-озвучка (ElevenLabs), YouTube.
6. Content Creator: рост YouTube-каналов, стратегия, retention, AdSense, спонсоры, SMM, AI-контент.
7. Affiliate BD: iGaming трафик и аффилейт, multi-GEO, поиск и онбординг партнеров, рефералки, SEO, креативы, аналитика.
8. Frontend: React, Next.js, TypeScript, Node.js, Tailwind, REST, WebSocket, Telegram-боты.

Если не вакансия, верни {"is_vacancy": false}.
Если вакансия, верни JSON с полями: is_vacancy (true), date, channel, title, company, salary_min, salary_max, salary_period, salary_currency, employment, remote, location, relocation, level, stack, nice_to_have, english, responsibilities, requirements, benefits, contact, link, match_score (0-100, насколько подходит Антону по любому из 8 профилей), match_explanation (1-2 предложения), priority (P0-P3), cv_to_use (название самого подходящего из 8 резюме), status ("new"), notes, raw_text (исходный текст поста), approach_hint (что Антону подчеркнуть в отклике, честно, на основе его реального профиля). Поля, которых нет в посте, оставляй пустыми. Пиши по-русски.`;
return $input.all().map(it=>{
  const p=it.json;
  const text = (p.text && String(p.text).trim()) ? p.text : '(пустой пост, только медиа)';
  return { json: {
    row_id: p.channel + '_' + p.id,
    channel: p.channel, post_id: p.id, date: p.date, link: p.link, raw_text: p.text || '',
    body: { model: 'claude-sonnet-4-6', max_tokens: 8000, system: SYSTEM, messages: [{ role: 'user', content: 'Текст поста:\n' + text }] }
  }};
});

const ctx = $('Собрать запрос Claude').all();
const items = $input.all();
const out=[];
for(let i=0;i<items.length;i++){
  const c = ctx[i] ? ctx[i].json : {};
  const r = items[i].json;
  let txt='';
  try { txt = r && r.content && r.content[0] && r.content[0].text ? r.content[0].text : ''; } catch(e){}
  if(!txt) continue;
  let obj=null;
  try {
    const cleaned = String(txt).replace(/```json/gi,'').replace(/```/g,'').trim();
    const s=cleaned.indexOf('{'); const e=cleaned.lastIndexOf('}');
    obj = JSON.parse(s>=0 && e>=0 ? cleaned.slice(s,e+1) : cleaned);
  } catch(e){ continue; }
  if(!obj || obj.is_vacancy!==true) continue;
  const g=(k)=>{ const v=obj[k]; if(v==null) return ''; if(Array.isArray(v)) return v.join('; '); if(typeof v==='object') return JSON.stringify(v); return v; };
  out.push({ json: {
    row_id: c.row_id || ((c.channel||'')+'_'+(c.post_id||'')),
    is_vacancy: true,
    date: c.date || g('date') || '',
    channel: c.channel || g('channel') || '',
    title: g('title'), company: g('company'),
    salary_min: g('salary_min'), salary_max: g('salary_max'), salary_period: g('salary_period'), salary_currency: g('salary_currency'),
    employment: g('employment'), remote: g('remote'), location: g('location'), relocation: g('relocation'),
    level: g('level'), stack: g('stack'), nice_to_have: g('nice_to_have'), english: g('english'),
    responsibilities: g('responsibilities'), requirements: g('requirements'), benefits: g('benefits'),
    contact: g('contact'), link: c.link || g('link') || '',
    match_score: g('match_score'), match_explanation: g('match_explanation'),
    priority: g('priority'), cv_to_use: g('cv_to_use'),
    status: g('status') || 'new', notes: g('notes'),
    raw_text: c.raw_text || g('raw_text') || '',
    approach_hint: g('approach_hint')
  }});
}
return out;

function esc(s){ return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
const vac = $('Разобрать ответ').all().map(i=>i.json)
  .filter(v => Number(v.match_score) >= 40)
  .sort((a,b)=> Number(b.match_score) - Number(a.match_score));
return vac.map(v=>{
  const sal = [v.salary_min, v.salary_max].filter(x=>x!=='' && x!=null).join(' - ');
  const salStr = sal ? (sal + ' ' + (v.salary_currency||'')).trim() : 'не указана';
  let remote; if (v.remote===true) remote='удалёнка'; else if (v.remote===false) remote = (v.location? esc(v.location) : 'офис'); else if (v.remote!=='' && v.remote!=null) remote=esc(v.remote); else remote='не указано';
  const lines = [
    '💼 <b>'+esc(v.title||'Вакансия')+'</b>'+(v.company?' — '+esc(v.company):''),
    '💰 '+esc(salStr)+'  |  🏠 '+remote,
    '🎯 match '+esc(v.match_score)+'  |  CV: '+esc(v.cv_to_use||'—'),
    (v.approach_hint? '💡 '+esc(v.approach_hint):''),
    '🔗 '+esc(v.link||'')
  ].filter(Boolean);
  return { json: { row_id: v.row_id, text: lines.join('\n') } };
});
